// Verify VisionQuest's HMAC-SHA256 signature before doing anything.
// VisionQuest signs JSON.stringify(envelope); for our ASCII payloads,
// re-stringifying the parsed body reproduces the exact bytes.
const crypto = require('crypto');
const secret = $env.VISIONQUEST_WEBHOOK_SECRET || '';
const item = $input.first().json;
const headers = item.headers || {};
const sig = headers['x-visionquest-signature'] || '';
const body = item.body;
const raw = typeof body === 'string' ? body : JSON.stringify(body);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(raw, 'utf8').digest('hex');
let valid = false;
try {
  valid = sig.length === expected.length &&
    crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected));
} catch (e) { valid = false; }
const envelope = typeof body === 'string' ? JSON.parse(body) : body;
return [{ json: { valid, type: envelope.type, data: envelope.data || {} } }];

